const allGuideTranslations: Record<string, Partial<GT>> = { it, en, es, fr, de, ja, zh, ko, pt, ru, pl };

export function getGuideTranslations(lang: string): GT {
  // Fallback PER-CHIAVE: l'inglese (completo) fa da base, la lingua scelta
  // sovrascrive le chiavi che definisce. Così chiavi nuove tradotte solo in
  // it/en restano comunque mostrate (in EN) in tutte le altre lingue.
  return { ...en, ...(allGuideTranslations[lang] || {}) } as GT;
}

